package main

import "fmt"

// ---- Nested structs ----
type Position struct {
    X, Y float64
}

type Stats struct {
    Health int
    Attack int
    Defense int
}

type Player struct {
    Name     string
    Position Position
    Stats    Stats
    Level    int
}

// ---- Embedded structs ----
type Character struct {
    Name  string
    Stats Stats  // Embedded field
}

// ---- Struct with embedded field ----
type Enemy struct {
    Name     string
    Position Position
    Stats    Stats
    IsBoss   bool
}

func main() {
    // ---- Nested structs ----
    player := Player{
        Name: "Hero",
        Position: Position{X: 10, Y: 20},
        Stats: Stats{Health: 100, Attack: 20, Defense: 10},
        Level: 5,
    }

    fmt.Println("Player:", player)
    fmt.Println("Position:", player.Position.X, player.Position.Y)
    fmt.Println("Health:", player.Stats.Health)
    fmt.Println("Attack:", player.Stats.Attack)

    // ---- Modifying nested fields ----
    player.Position.X = 15
    player.Stats.Health = 80
    fmt.Println("After modification:", player)

    // ---- Embedded structs ----
    enemy := Enemy{
        Name: "Goblin",
        Position: Position{X: 5, Y: 10},
        Stats: Stats{Health: 30, Attack: 8, Defense: 3},
        IsBoss: false,
    }

    fmt.Println("Enemy:", enemy)

    // ---- Struct with embedded field ----
    character := Character{
        Name: "Aragorn",
        Stats: Stats{Health: 120, Attack: 25, Defense: 15},
    }

    fmt.Println("Character:", character)

    // ---- Comparing nested structs ----
    p1 := Player{
        Name: "Hero",
        Position: Position{X: 10, Y: 20},
        Stats: Stats{Health: 100, Attack: 20, Defense: 10},
        Level: 5,
    }

    p2 := Player{
        Name: "Hero",
        Position: Position{X: 10, Y: 20},
        Stats: Stats{Health: 100, Attack: 20, Defense: 10},
        Level: 5,
    }

    fmt.Println("p1 == p2:", p1 == p2)
}

