package main

import "fmt"

type Position struct {
    X, Y float64
}

type Stats struct {
    Health  int
    Attack  int
    Defense int
}

type Player struct {
    Name     string
    Position Position
    Stats    Stats
}

func main() {
    player := Player{
        Name:     "Hero",
        Position: Position{X: 10, Y: 20},
        Stats:    Stats{Health: 100, Attack: 20, Defense: 10},
    }
    fmt.Println("Player:", player)

    player.Stats.Health = 80
    fmt.Println("After modification:", player)
}
